class FoodRatings:
    def __init__(self, foods: List[str], cuisines: List[str], ratings: List[int]):
        self.food_ratings = {food: (rating, idx) for idx, (food, rating) in enumerate(zip(foods, ratings))}
        self.cuisine_ratings = {}
        for idx, (food, cuisine, rating) in enumerate(zip(foods, cuisines, ratings)):
            if cuisine not in self.cuisine_ratings:
                self.cuisine_ratings[cuisine] = []
            self.cuisine_ratings[cuisine].append((rating, idx, food))

    def changeRating(self, food: str, newRating: int) -> None:
        old_rating, idx = self.food_ratings[food]
        self.cuisine_ratings[self.cuisines[idx]].remove((old_rating, idx, food))
        self.cuisine_ratings[self.cuisines[idx]].append((newRating, idx, food))
        self.cuisine_ratings[self.cuisines[idx]].sort(reverse=True)

    def highestRated(self, cuisine: str) -> str:
        return min((rating, food) for rating, _, food in self.cuisine_ratings[cuisine])[1]
